import { httpsAgentForURL } from './https-agent-for-url';

export function buildAxiosRequestConfig(
  method: string,
  url: string,
  headers: any,
  data?: any,
) {
  const config: any = {
    method,
    url,
    headers,
    httpsAgent: httpsAgentForURL(url),
  };
  // Add optional request attribtues
  if (data) {
    config.data = data;
  }
  return config;
}
